/* ═══════════════════════════════════════
   SCREEN: LOGIN
═══════════════════════════════════════ */
reg('login',el=>{
  el.id='s-login';
  el.innerHTML=`
    <div class="login-top">
    <div class="login-title">
      <span class="star-ico">★</span>
      כתוב בכוכבים
      <span class="star-ico">★</span>
    </div>
    <div class="login-card">
      <h2>התחברות</h2>
      <form id="login-form" autocomplete="off">
      <div class="fg"><label>שם משתמש:</label><input id="ln" type="text" placeholder="" autocomplete="off"/></div>
      <div class="fg"><label>סיסמה:</label><input id="lp" type="password" placeholder=""/></div>
      </form>
      <p class="role-label">התחברות כ:</p>
      <div class="role-row">
        <button class="rbtn rbtn-p" id="login-pl"><span class="rico">🎮</span><span>שחקן</span></button>
        <button class="rbtn rbtn-a" id="login-ad"><span class="rico">👑</span><span>מנהל</span></button>
      </div>
      <button class="link-btn" id="goto-reg">משתמש חדש? הירשם כאן</button>
    </div>
    </div>

    <div class="planet-strip-wrap" aria-hidden="true">
      <div class="planet-strip"><div class="planet-item"><img src="data:image/png;base64," width="150" height="150" class="planet-float" style="animation-duration:8s;animation-delay:0s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="120" height="120" class="planet-float" style="animation-duration:11s;animation-delay:-2s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="110" height="110" class="planet-float" style="animation-duration:7s;animation-delay:-1s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="145" height="145" class="planet-float" style="animation-duration:9s;animation-delay:-1.5s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="95" height="95" class="planet-float" style="animation-duration:13s;animation-delay:-0.5s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="115" height="115" class="planet-float" style="animation-duration:6s;animation-delay:-4s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="105" height="105" class="planet-float" style="animation-duration:10s;animation-delay:-3s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="100" height="100" class="planet-float" style="animation-duration:12s;animation-delay:-2.5s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="150" height="150" class="planet-float" style="animation-duration:8s;animation-delay:0s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="120" height="120" class="planet-float" style="animation-duration:11s;animation-delay:-2s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="110" height="110" class="planet-float" style="animation-duration:7s;animation-delay:-1s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="145" height="145" class="planet-float" style="animation-duration:9s;animation-delay:-1.5s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="95" height="95" class="planet-float" style="animation-duration:13s;animation-delay:-0.5s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="115" height="115" class="planet-float" style="animation-duration:6s;animation-delay:-4s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="105" height="105" class="planet-float" style="animation-duration:10s;animation-delay:-3s;" alt=""/></div><div class="planet-item"><img src="data:image/png;base64," width="100" height="100" class="planet-float" style="animation-duration:12s;animation-delay:-2.5s;" alt=""/></div></div>
    </div`;

  function doLogin(role){
    const name=document.getElementById('ln').value.trim();
    const pass=document.getElementById('lp').value.trim();
    if(!name||!pass){showToast('נא למלא שם וסיסמה','warn');return;}
    const users=getUsers();
    const byName=users.find(u=>u.name.toLowerCase()===name.toLowerCase());
    if(!byName){go('register',{name,pass});return;}
    const user=users.find(u=>u.name.toLowerCase()===name.toLowerCase()&&u.password===pass);
    if(!user){showToast('סיסמה שגויה — אנא נסה שנית','error');return;}
    if(role==='admin'&&user.role!=='admin'){showToast('חשבון זה הוא חשבון שחקן — אנא התחבר כשחקן','warn');return;}
    if(role==='player'&&user.role!=='player'){showToast('חשבון זה הוא חשבון מנהל — אנא התחבר כמנהל','warn');return;}
    saveSession(user);
    if(user.role==='admin')go('admin');else go('gamesel');
  }
  document.getElementById('login-pl').onclick=()=>doLogin('player');
  document.getElementById('login-ad').onclick=()=>doLogin('admin');
  document.getElementById('goto-reg').onclick=()=>go('register',{});
  document.getElementById('login-form').addEventListener('submit',(e)=>{e.preventDefault();doLogin('player')});
  el.querySelectorAll('input').forEach(i=>i.addEventListener('keydown',e=>{if(e.key==='Enter'){e.preventDefault();doLogin('player')}}));
  // Fix carousel glitch: measure exact pixel width and override animation
  requestAnimationFrame(()=>{
    const strip=el.querySelector('.planet-strip');
    if(!strip)return;
    const hw=Math.round(strip.scrollWidth/2);
    let s=document.getElementById('_car_fix');
    if(!s){s=document.createElement('style');s.id='_car_fix';document.head.appendChild(s);}
    s.textContent=`@keyframes scrollPlanets{0%{transform:translate3d(0,0,0)}100%{transform:translate3d(-${hw}px,0,0)}}`;
  });
});

/* ═══════════════════════════════════════
   SCREEN: REGISTER
═══════════════════════════════════════ */
reg('register',(el,d)=>{
  el.innerHTML=`
    <div class="card reg-card">
      <h2>✦ הרשמה ✦</h2>
      <div class="fg"><label>שם:</label><input id="rn" type="text" value="${d.name||''}" placeholder="שם משתמש..."/></div>
      <div class="fg"><label>סיסמה:</label><input id="rp" type="password" value="${d.pass||''}" placeholder="סיסמה..."/></div>
      <p style="text-align:center;font-size:16px;font-weight:700;color:rgba(10,30,100,.7);margin-bottom:12px;">להרשמה כ:</p>
      <div class="reg-opts">
        <button class="ropt ropt-p" id="ro-pl"><span class="ropt-ico">🎮</span><span>שחקן</span></button>
        <button class="ropt ropt-a" id="ro-ad"><span class="ropt-ico">👑</span><span>מנהל</span></button>
      </div>
      <div class="code-area" id="code-area">
        <p style="font-size:14px;color:rgba(10,30,100,.7);text-align:center;margin-bottom:6px;">הכנס קוד מנהל:</p>
        <div class="pw-wrap"><input type="password" class="code-inp" id="acode" maxlength="32" placeholder="********"/>${eyeBtn('acode')}</div>
        <button class="btn btn-purple btn-full" id="confirm-ad">אישור</button>
      </div>
      <div id="pl-area" style="display:none;margin-top:10px;">
        <button class="btn btn-navy btn-full" id="confirm-pl">הירשם כשחקן</button>
      </div>
      <button class="link-btn" id="back-reg">חזרה לכניסה</button>
    </div>
    ${mascotHTML('NanySaysHello','br','big','NanySaysHelloForSmallDevices')}`;

  document.getElementById('back-reg').onclick=()=>go('login');
  document.getElementById('ro-ad').onclick=()=>{
    document.getElementById('code-area').classList.add('show');
    document.getElementById('pl-area').style.display='none';
  };
  document.getElementById('ro-pl').onclick=()=>{
    document.getElementById('code-area').classList.remove('show');
    document.getElementById('pl-area').style.display='block';
  };
  async function doReg(role){
    const name=document.getElementById('rn').value.trim();
    const pass=document.getElementById('rp').value.trim();
    if(!name||!pass){showToast('נא למלא שם וסיסמה','warn');return;}
    const users=getUsers();
    if(users.find(u=>u.name.toLowerCase()===name.toLowerCase())){
      showToast('המשתמש כבר קיים במערכת — אנא בחר שם אחר','error');return;
    }
    if(role==='admin'){
      const entered=document.getElementById('acode').value.trim();
      if(!ADMIN_CODE_HASHES.includes(await sha256Hex(entered))){
        showToast('קוד מנהל שגוי — פנה למנהל המערכת','error');return;
      }
    }
    const u={id:'u'+Date.now(),name,password:pass,role,score:0,
      avatar:AVATARS[Math.floor(Math.random()*AVATARS.length)],createdAt:new Date().toISOString()};
    users.push(u);saveUsers(users);
    showToast('נרשמת בהצלחה! ברוך הבא 🎉','ok',3000);
    saveSession(u);
    setTimeout(()=>{if(role==='admin')go('admin');else go('gamesel');},600);
  }
  document.getElementById('confirm-ad').onclick=()=>doReg('admin');
  document.getElementById('confirm-pl').onclick=()=>doReg('player');
});


