// האזנה על כל הדף (לא רק על input ספציפי)
document.addEventListener('input', function(e) {
    // בדוק אם האירוע בא משדה שם משתמש
    if (e.target && e.target.id === 'ln') {
        console.log('נכתב:', e.target.value);
    }
});